var todayStr = new Date().toISOString().split('T')[0];
let dFrom = new Date().getFullYear() + '-01-01';
let dTo = todayStr;

function fmt(v) { return '$' + (typeof v === 'number' ? v.toLocaleString(undefined, {minimumFractionDigits:2, maximumFractionDigits:2}) : v); }
function fmtN(v) { return Math.round(v).toLocaleString(); }
function fmtP(v) { return (v * 100).toFixed(2) + '%'; }
function filterByDate(data, from, to) { return data.filter(function(r) { return r.date >= from && r.date <= to; }); }
function tryStorage(fn) { try { return fn(); } catch(e) { return null; } }
function getDayName(dateStr) {
  var days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  return days[new Date(dateStr + 'T12:00:00').getDay()];
}
function getDayShort(dateStr) {
  var days = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  return days[new Date(dateStr + 'T12:00:00').getDay()];
}
function fmtDate(d) {
  var parts = d.split('-');
  return parts[1] + '/' + parts[2];
}

function getAmazon(date) {
  var r = AMAZON_DATA.find(function(x) { return x.date === date; });
  return r || {date: date, sessions: 0, units: 0, sales: 0, orders: 0};
}
function getWalmart(date) {
  var r = WALMART_DATA.find(function(x) { return x.date === date; });
  return r || {date: date, tv_units: 0, soundbar_units: 0, total_units: 0, retail: 0};
}

function getAllDates(from, to) {
  var dateSet = {};
  var allData = [GA4_DATA, META_DAILY_DATA, SHOPIFY_DATA, TIKTOK_DATA, VIBE_DATA, AMAZON_DATA, WALMART_DATA];
  allData.forEach(function(arr) {
    arr.forEach(function(r) {
      if (r.date >= from && r.date <= to) dateSet[r.date] = true;
    });
  });
  GOOGLE_ADS_DATA.forEach(function(r) {
    if (r.date >= from && r.date <= to) dateSet[r.date] = true;
  });
  return Object.keys(dateSet).sort();
}



function initDateInputs() {
  document.getElementById('dFrom').value = dFrom;
  document.getElementById('dTo').value = dTo;
}

function getDateRangeLabel() {
  var year = new Date().getFullYear();
  var jan1 = year + '-01-01';
  if (dFrom === jan1 && dTo === todayStr) {
    return 'Year To Date (YTD) ' + year;
  }
  return fmtDate(dFrom) + ' — ' + fmtDate(dTo);
}

function updateDateSubtitle() {
  var el = document.getElementById('dateRangeSubtitle');
  if (el) {
    el.innerHTML = '<span style="color:var(--muted);font-size:13px">Select a date range above for specific analysis</span><br><span style="color:var(--gold);font-size:15px;font-weight:600">' + getDateRangeLabel() + '</span>';
  }
}

function checkPassword() {
  var pw = document.getElementById('pwInput').value;
  if (pw === atob('SGFuZ3NtYXJ0MSE=')) {
    tryStorage(function() { localStorage.setItem('hs_auth', 'true'); });
    document.getElementById('loginOverlay').classList.add('hidden');
    document.getElementById('dashboardWrap').style.display = 'block';
    initDateInputs();
    renderAll();
  } else {
    document.getElementById('pwError').style.display = 'block';
  }
}



function switchTab(tabName) {
  document.querySelectorAll('.tab-panel').forEach(function(p) { p.classList.remove('active'); });
  document.querySelectorAll('.nav-btn').forEach(function(b) { b.classList.remove('active'); });
  document.getElementById(tabName).classList.add('active');
  document.querySelector('[data-tab="' + tabName + '"]').classList.add('active');
}

function applyDateFilter() {
  dFrom = document.getElementById('dFrom').value;
  dTo = document.getElementById('dTo').value;
  updateDateSubtitle();
  renderAll();
}



function renderOverview() {
  var dates = getAllDates(dFrom, dTo);
  var numDays = dates.length;

  var totalAdSpend = 0, totalShopifyOrders = 0, totalAmazonOrders = 0, totalWalmartUnits = 0;
  var totalAmazonSales = 0, totalWalmartSales = 0, totalShopifySales = 0;
  var totalGA4Sessions = 0, totalGA4Transactions = 0;

  dates.forEach(function(d) {
    var meta = META_DAILY_DATA.find(function(x){return x.date===d;});
    var gAds = GOOGLE_ADS_DATA.filter(function(x){return x.date===d;});
    var vibe = VIBE_DATA.filter(function(x){return x.date===d;});
    var shop = SHOPIFY_DATA.find(function(x){return x.date===d;});
    var ga = GA4_DATA.find(function(x){return x.date===d;});
    var amz = getAmazon(d);
    var wmt = getWalmart(d);

    if(meta) totalAdSpend += meta.spend;
    gAds.forEach(function(g){totalAdSpend += g.spend;});
    vibe.forEach(function(v){totalAdSpend += v.spend;});
    if(shop) { totalShopifyOrders += shop.orders; totalShopifySales += shop.revenue; }
    totalAmazonOrders += amz.orders;
    totalAmazonSales += amz.units * 18.50;
    totalWalmartUnits += wmt.total_units;
    totalWalmartSales += wmt.total_units * 19;
    if(ga) { totalGA4Sessions += ga.sessions; totalGA4Transactions += ga.transactions; }
  });

  var totalAmazonUnits = AMAZON_DATA.filter(function(a) { return a.date >= dFrom && a.date <= dTo; }).reduce(function(s, a) { return s + a.units; }, 0);
  var totalEstUnits = totalShopifyOrders + totalAmazonUnits + totalWalmartUnits;
  var totalRevenue = totalShopifySales + totalAmazonSales + totalWalmartSales;
  var blendedROAS = totalAdSpend > 0 ? (totalRevenue / totalAdSpend).toFixed(2) : 'N/A';
  var avgOrderValue = totalEstUnits > 0 ? (totalRevenue / totalEstUnits).toFixed(2) : 'N/A';
  var cvr = totalGA4Sessions > 0 ? ((totalGA4Transactions / totalGA4Sessions) * 100).toFixed(2) + '%' : 'N/A';
  var costPerTx = totalEstUnits > 0 ? (totalAdSpend / totalEstUnits).toFixed(2) : 'N/A';

  var html = '';
  html += '<div class="card"><h3>Total Ad Spend</h3><div class="value">' + fmt(totalAdSpend) + '</div></div>';
  html += '<div class="card"><h3>Blended ROAS</h3><div class="value" style="color:var(--gold)">' + blendedROAS + 'x</div></div>';
  html += '<div class="card"><h3>Average Order Value</h3><div class="value">' + fmt(parseFloat(avgOrderValue)) + '</div></div>';
  html += '<div class="card"><h3>Shopify Orders</h3><div class="value">' + fmtN(totalShopifyOrders) + '</div></div>';
  html += '<div class="card"><h3>Amazon Units</h3><div class="value">' + fmtN(totalAmazonUnits) + '</div></div>';
  html += '<div class="card"><h3>Walmart Units</h3><div class="value">' + fmtN(totalWalmartUnits) + '</div></div>';
  html += '<div class="card"><h3>Total Est. Units</h3><div class="value">' + fmtN(totalEstUnits) + '</div></div>';
  html += '<div class="card"><h3>GA4 Sessions</h3><div class="value">' + fmtN(totalGA4Sessions) + '</div></div>';
  html += '<div class="card"><h3>Conversion Rate</h3><div class="value">' + cvr + '</div></div>';
  html += '<div class="card"><h3>Cost Per Unit</h3><div class="value">' + fmt(parseFloat(costPerTx)) + '</div></div>';
  document.getElementById('overviewCards').innerHTML = html;

  var summaryHtml = '<strong>Summary Analysis (' + fmtDate(dFrom) + ' - ' + fmtDate(dTo) + '):</strong> ';
  summaryHtml += 'Over this ' + numDays + '-day period, HangSmart generated an estimated <strong>' + fmtN(totalEstUnits) + ' total units</strong> across all sales channels with <strong>' + fmt(totalRevenue) + ' in HangSmart net revenue</strong> (Shopify at actual SKU-level retail pricing, Amazon at $18.50/unit wholesale, Walmart at $19/unit wholesale). ';
  summaryHtml += 'Total ad spend was <strong>' + fmt(totalAdSpend) + '</strong> yielding a blended ROAS of <strong>' + blendedROAS + 'x</strong>. ';
  if(totalShopifyOrders > 0) summaryHtml += 'Shopify accounted for <strong>' + fmtN(totalShopifyOrders) + ' orders</strong> (' + ((totalShopifyOrders/totalEstUnits)*100).toFixed(1) + '% of total units). ';
  if(totalAmazonUnits > 0) summaryHtml += 'Amazon drove <strong>' + fmtN(totalAmazonUnits) + ' units</strong> (' + ((totalAmazonUnits/totalEstUnits)*100).toFixed(1) + '%). ';
  if(totalWalmartUnits > 0) summaryHtml += 'Walmart contributed <strong>' + fmtN(totalWalmartUnits) + ' units</strong> (' + ((totalWalmartUnits/totalEstUnits)*100).toFixed(1) + '%). ';
  if(totalGA4Sessions > 0) summaryHtml += 'The website averaged <strong>' + fmtN(Math.round(totalGA4Sessions/numDays)) + ' sessions/day</strong> with a <strong>' + cvr + ' conversion rate</strong>.';
  document.getElementById('summaryAnalysis').innerHTML = summaryHtml;

  renderDOWTable(dates);

  renderDailyBlended(dates);

  renderTopBottomDays(dates);

  renderOverviewCampaigns();

  // Attribution Analysis - insert between cards and summary
  var attrDiv = document.getElementById('attributionAnalysis');
  if (!attrDiv) {
    attrDiv = document.createElement('div');
    attrDiv.id = 'attributionAnalysis';
    attrDiv.className = 'summary-box';
    var summaryEl = document.getElementById('summaryAnalysis');
    if (summaryEl && summaryEl.parentNode) {
      summaryEl.parentNode.insertBefore(attrDiv, summaryEl);
    }
  }

  var attrHtml = '<strong style="font-size:16px;color:var(--gold)">Ad Spend Attribution Analysis</strong>';
  attrHtml += '<p style="color:var(--muted);margin:8px 0 16px">Monthly correlation between total ad spend and total units sold across all channels (Apr 2024 - Apr 2026)</p>';

  // Compute monthly Amazon & Walmart units from raw data
  var amzByMonth = {}, wmtByMonth = {};
  AMAZON_DATA.forEach(function(a) { var mo = a.date.substring(0,7); amzByMonth[mo] = (amzByMonth[mo]||0) + (a.units||0); });
  WALMART_DATA.forEach(function(w) { var mo = w.date.substring(0,7); wmtByMonth[mo] = (wmtByMonth[mo]||0) + (w.total_units||0); });

  // Build monthly table with blended units
  var organicFloor = 460;
  attrHtml += '<table><thead><tr><th>Month</th><th style="text-align:right">Total Ad Spend</th><th style="text-align:right">Shopify Orders</th><th style="text-align:right">Amazon Units</th><th style="text-align:right">Walmart Units</th><th style="text-align:right">Total Units</th><th style="text-align:right">Spend vs Prev</th><th style="text-align:right">Units vs Prev</th></tr></thead><tbody>';
  var prev = null;
  MONTHLY_HISTORY.forEach(function(m) {
    var totalSpend = m.fb_spend + m.gads_spend + m.tt_spend + m.vibe_spend;
    var shopifyOrders = m.ga4_transactions;
    var amzUnits = amzByMonth[m.month] || 0;
    var wmtUnits = wmtByMonth[m.month] || 0;
    var totalUnits = shopifyOrders + amzUnits + wmtUnits;
    var spendChg = prev ? ((totalSpend - prev.spend) / prev.spend * 100).toFixed(1) : '-';
    var unitChg = prev ? ((totalUnits - prev.units) / prev.units * 100).toFixed(1) : '-';
    var spendColor = spendChg !== '-' ? (parseFloat(spendChg) >= 0 ? 'var(--green)' : 'var(--red)') : 'inherit';
    var unitColor = unitChg !== '-' ? (parseFloat(unitChg) >= 0 ? 'var(--green)' : 'var(--red)') : 'inherit';
    attrHtml += '<tr><td style="font-weight:600">' + m.month + '</td>';
    attrHtml += '<td style="text-align:right">' + fmt(totalSpend) + '</td>';
    attrHtml += '<td style="text-align:right">' + fmtN(shopifyOrders) + '</td>';
    attrHtml += '<td style="text-align:right">' + (amzUnits > 0 ? fmtN(amzUnits) : '<span style="color:var(--muted)">—</span>') + '</td>';
    attrHtml += '<td style="text-align:right">' + (wmtUnits > 0 ? fmtN(wmtUnits) : '<span style="color:var(--muted)">—</span>') + '</td>';
    attrHtml += '<td style="text-align:right;font-weight:600">' + fmtN(totalUnits) + '</td>';
    attrHtml += '<td style="text-align:right;color:' + spendColor + '">' + (spendChg !== '-' ? spendChg + '%' : '-') + '</td>';
    attrHtml += '<td style="text-align:right;color:' + unitColor + '">' + (unitChg !== '-' ? unitChg + '%' : '-') + '</td></tr>';
    prev = {spend: totalSpend, units: totalUnits};
  });
  attrHtml += '</tbody></table>';

  // Key insights — blended across all channels
  var recentMonths = MONTHLY_HISTORY.filter(function(m) { return m.month >= '2025-11'; });
  var totalRecentSpend = 0, totalRecentShopify = 0, totalRecentAmz = 0, totalRecentWmt = 0;
  recentMonths.forEach(function(m) {
    totalRecentSpend += m.fb_spend + m.gads_spend + m.tt_spend + m.vibe_spend;
    totalRecentShopify += m.ga4_transactions;
    totalRecentAmz += (amzByMonth[m.month] || 0);
    totalRecentWmt += (wmtByMonth[m.month] || 0);
  });
  var avgMonthlySpend = totalRecentSpend / recentMonths.length;
  var totalRecentUnits = totalRecentShopify + totalRecentAmz + totalRecentWmt;
  var avgMonthlyUnits = totalRecentUnits / recentMonths.length;
  var hasMarketplace = totalRecentAmz > 0 || totalRecentWmt > 0;
  var shopifyPct = hasMarketplace ? ((totalRecentShopify / totalRecentUnits) * 100).toFixed(1) : '100';
  var amzPct = hasMarketplace ? ((totalRecentAmz / totalRecentUnits) * 100).toFixed(1) : '0';
  var wmtPct = hasMarketplace ? ((totalRecentWmt / totalRecentUnits) * 100).toFixed(1) : '0';

  attrHtml += '<div style="margin-top:16px;padding:16px;background:rgba(212,175,55,0.08);border-radius:8px;border-left:3px solid var(--gold)">';
  attrHtml += '<strong>Key Findings:</strong><br>';
  attrHtml += '- <strong>Recent avg:</strong> ' + fmt(avgMonthlySpend) + '/month spend driving ~' + fmtN(Math.round(avgMonthlyUnits)) + ' total units/month across all channels<br>';
  if (hasMarketplace) {
    attrHtml += '- <strong>Channel split:</strong> Shopify ' + shopifyPct + '% | Amazon ' + amzPct + '% | Walmart ' + wmtPct + '%<br>';
  }
  attrHtml += '- <strong>Pattern:</strong> When ad spend scaled from ~$30K (Q1 2025) to ~$110K+ (Q4 2025-Q1 2026), transactions increased ~3x, confirming strong paid-to-sale correlation<br>';
  attrHtml += '- <strong>Note:</strong> Amazon and Walmart unit data available from Jan 2026 onward. Pre-2026 months show Shopify orders only (marked with — for marketplace columns).';
  attrHtml += '</div>';

  attrDiv.innerHTML = attrHtml;

  // ── OPTIMIZATION SCORE ───────────────────────────────────────────────────────
  // Score 0–100 based on: Meta CTR, Meta CPC, blended ROAS, CVR, campaign health signals
  // Scoring is relative to HangSmart benchmarks, not industry averages
  (function() {
    var score = 0;
    var maxScore = 100;

    // 1. Blended ROAS (30 pts): ≥4.0=30, ≥3.0=24, ≥2.0=18, ≥1.5=12, ≥1.0=6, <1.0=0
    var bROAS = parseFloat(blendedROAS) || 0;
    var roasScore = bROAS >= 4.0 ? 30 : bROAS >= 3.0 ? 24 : bROAS >= 2.0 ? 18 : bROAS >= 1.5 ? 12 : bROAS >= 1.0 ? 6 : 0;
    score += roasScore;

    // 2. Meta CTR (20 pts): compute from META_DAILY_DATA in range
    var metaF2 = filterByDate(META_DAILY_DATA, dFrom, dTo);
    var totalImpr = metaF2.reduce(function(s,r){return s+(r.impressions||0);},0);
    var totalClicks = metaF2.reduce(function(s,r){return s+(r.clicks||0);},0);
    var metaCTR = totalImpr > 0 ? (totalClicks / totalImpr * 100) : 0;
    var ctrScore = metaCTR >= 3.5 ? 20 : metaCTR >= 2.5 ? 16 : metaCTR >= 2.0 ? 12 : metaCTR >= 1.5 ? 8 : metaCTR >= 1.0 ? 4 : 0;
    score += ctrScore;

    // 3. Meta CPC (15 pts): ≤$0.60=15, ≤$0.90=12, ≤$1.25=9, ≤$1.75=6, ≤$2.50=3, >$2.50=0
    var metaSpendF = metaF2.reduce(function(s,r){return s+r.spend;},0);
    var metaCPC = totalClicks > 0 ? (metaSpendF / totalClicks) : 99;
    var cpcScore = metaCPC <= 0.60 ? 15 : metaCPC <= 0.90 ? 12 : metaCPC <= 1.25 ? 9 : metaCPC <= 1.75 ? 6 : metaCPC <= 2.50 ? 3 : 0;
    score += cpcScore;

    // 4. Conversion Rate from GA4 (15 pts): ≥3.0%=15, ≥2.5%=12, ≥2.0%=9, ≥1.5%=6, ≥1.0%=3, <1.0%=0
    var cvrNum = totalGA4Sessions > 0 ? (totalGA4Transactions / totalGA4Sessions * 100) : 0;
    var cvrScore = cvrNum >= 3.0 ? 15 : cvrNum >= 2.5 ? 12 : cvrNum >= 2.0 ? 9 : cvrNum >= 1.5 ? 6 : cvrNum >= 1.0 ? 3 : 0;
    score += cvrScore;

    // 5. Campaign Health Penalty (−20 pts max): deduct for known waste running in the account
    // Based on static analysis: soundbar campaigns + catalog BOF still active = -12; CTV waste ads = -5; nothing paused yet = -8
    // As of Apr 13 2026 first report: -15 because 5 flagged campaigns/ads are still running
    var campaignPenalty = -15;
    score += campaignPenalty;

    // 6. Amazon + Walmart Data Coverage (10 pts): if both channels have recent data bonus
    var hasAmzRecent = AMAZON_DATA.some(function(a){return a.date >= dTo.substring(0,7) + '-01';});
    var hasWmtRecent = WALMART_DATA.some(function(w){return w.date >= dTo.substring(0,7) + '-01';});
    score += (hasAmzRecent ? 5 : 0) + (hasWmtRecent ? 5 : 0);

    // Clamp 0–100
    score = Math.max(0, Math.min(100, Math.round(score)));

    // Color: ≥80=green, ≥60=gold, ≥40=warning orange, <40=red
    var scoreColor = score >= 80 ? 'var(--green)' : score >= 60 ? 'var(--gold)' : score >= 40 ? '#f59e0b' : 'var(--red)';
    var badge = document.getElementById('optimScoreBadge');
    var valEl = document.getElementById('optimScoreVal');
    var fillEl = document.getElementById('optimScoreFill');
    if (badge && valEl && fillEl) {
      badge.style.display = 'flex';
      badge.style.borderColor = scoreColor;
      valEl.textContent = score + '%';
      valEl.style.color = scoreColor;
      fillEl.style.width = score + '%';
      fillEl.style.background = scoreColor;
    }
  })();
}

function renderDOWTable(dates) {
  var dow = {};
  ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'].forEach(function(d){
    dow[d] = {txTotal:0,txShopify:0,txAmazon:0,txWalmart:0,sessions:0,count:0};
  });
  dates.forEach(function(d) {
    var day = getDayName(d);
    var shop = SHOPIFY_DATA.find(function(x){return x.date===d;});
    var ga = GA4_DATA.find(function(x){return x.date===d;});
    var amz = getAmazon(d);
    var wmt = getWalmart(d);
    var shopOrders = shop ? shop.orders : 0;
    dow[day].txShopify += shopOrders;
    dow[day].txAmazon += amz.orders;
    dow[day].txWalmart += wmt.total_units;
    dow[day].txTotal += shopOrders + amz.orders + wmt.total_units;
    dow[day].sessions += ga ? ga.sessions : 0;
    dow[day].count += 1;
  });

  var html = '<table class="perf-table"><thead><tr><th style="text-align:left">Day</th><th>Avg Total Transactions</th><th>Avg Shopify</th><th>Avg Amazon</th><th>Avg Walmart</th><th>Avg Sessions</th><th>Performance Tier</th></tr></thead><tbody>';
  var sorted = Object.keys(dow).sort(function(a,b){ return dow[b].txTotal/Math.max(dow[b].count,1) - dow[a].txTotal/Math.max(dow[a].count,1); });
  sorted.forEach(function(day) {
    var d = dow[day];
    if(d.count === 0) return;
    var avgTx = (d.txTotal / d.count).toFixed(1);
    var avgShop = (d.txShopify / d.count).toFixed(1);
    var avgAmz = (d.txAmazon / d.count).toFixed(1);
    var avgWmt = (d.txWalmart / d.count).toFixed(1);
    var avgSess = Math.round(d.sessions / d.count);
    var tier = avgTx >= 300 ? '<span class="tag tag-scale">Peak</span>' : avgTx >= 200 ? '<span class="tag tag-stable">Strong</span>' : avgTx >= 150 ? '<span class="tag tag-monitor">Average</span>' : '<span class="tag tag-underperform">Below Avg</span>';
    html += '<tr><td style="text-align:left;font-weight:600">' + day + '</td><td style="text-align:right;color:var(--gold);font-weight:700">' + avgTx + '</td><td style="text-align:right">' + avgShop + '</td><td style="text-align:right">' + avgAmz + '</td><td style="text-align:right">' + avgWmt + '</td><td style="text-align:right">' + fmtN(avgSess) + '</td><td style="text-align:right">' + tier + '</td></tr>';
  });
  html += '</tbody></table>';
  document.getElementById('dowTable').innerHTML = html;
}

