function renderTikTok() {
  var tt = filterByDate(TIKTOK_DATA, dFrom, dTo);
  var adsData = tt.filter(function(r){return r.type==='ads';});
  var gmvData = tt.filter(function(r){return r.type==='gmv_max';});
  var totalSpend = tt.reduce(function(s,r){return s+r.spend;},0);
  var adsSpend = adsData.reduce(function(s,r){return s+r.spend;},0);
  var gmvSpend = gmvData.reduce(function(s,r){return s+r.spend;},0);
  var totalImpressions = adsData.reduce(function(s,r){return s+r.impressions;},0);
  var totalClicks = adsData.reduce(function(s,r){return s+r.clicks;},0);
  var totalConversions = adsData.reduce(function(s,r){return s+r.conversions;},0);
  var totalReach = adsData.reduce(function(s,r){return s+r.reach;},0);
  var avgCTR = totalImpressions > 0 ? (totalClicks/totalImpressions*100).toFixed(2) : '—';
  var avgCPC = totalClicks > 0 ? (totalSpend/totalClicks).toFixed(2) : '—';
  var avgCPM = totalImpressions > 0 ? (totalSpend/totalImpressions*1000).toFixed(2) : '—';

  var html = '';
  html += '<div class="card"><h3>Total Spend</h3><div class="value">' + fmt(totalSpend) + '</div></div>';
  if (adsSpend > 0 && gmvSpend > 0) {
    html += '<div class="card"><h3>TikTok Ads Spend</h3><div class="value">' + fmt(adsSpend) + '</div></div>';
    html += '<div class="card"><h3>GMV Max Spend</h3><div class="value">' + fmt(gmvSpend) + '</div></div>';
  } else if (gmvSpend > 0) {
    html += '<div class="card"><h3>GMV Max Spend</h3><div class="value">' + fmt(gmvSpend) + '</div></div>';
  }
  if (totalImpressions > 0) {
    html += '<div class="card"><h3>Impressions</h3><div class="value">' + fmtN(totalImpressions) + '</div></div>';
    html += '<div class="card"><h3>Clicks</h3><div class="value">' + fmtN(totalClicks) + '</div></div>';
    html += '<div class="card"><h3>CTR</h3><div class="value">' + avgCTR + '%</div></div>';
    html += '<div class="card"><h3>Avg CPC</h3><div class="value">' + fmt(parseFloat(avgCPC)) + '</div></div>';
    html += '<div class="card"><h3>Avg CPM</h3><div class="value">' + fmt(parseFloat(avgCPM)) + '</div></div>';
    html += '<div class="card"><h3>Conversions</h3><div class="value">' + fmtN(totalConversions) + '</div></div>';
    html += '<div class="card"><h3>Reach</h3><div class="value">' + fmtN(totalReach) + '</div></div>';
  }
  if (gmvSpend > 0 && adsSpend === 0) {
    html += '<p style="color:var(--muted);margin-top:12px;font-size:13px">GMV Max reports spend only through Windsor. Impressions, clicks, and conversion metrics are available in TikTok Ads Manager.</p>';
  }
  document.getElementById('tiktokCards').innerHTML = html;

  // Campaign breakdown
  var camps = {};
  tt.forEach(function(r) {
    if (!camps[r.campaign]) camps[r.campaign] = {spend:0,impressions:0,clicks:0,conversions:0,reach:0,days:0,type:r.type};
    camps[r.campaign].spend += r.spend;
    camps[r.campaign].impressions += r.impressions;
    camps[r.campaign].clicks += r.clicks;
    camps[r.campaign].conversions += r.conversions;
    camps[r.campaign].reach += r.reach;
    camps[r.campaign].days += 1;
  });
  var campHtml = '<div class="section-title">Campaign Breakdown</div>';
  campHtml += '<table><thead><tr><th>Campaign</th><th style="text-align:right">Type</th><th style="text-align:right">Spend</th><th style="text-align:right">Impressions</th><th style="text-align:right">Clicks</th><th style="text-align:right">CTR</th><th style="text-align:right">Conversions</th><th style="text-align:right">Days Active</th></tr></thead><tbody>';
  Object.keys(camps).sort(function(a,b){return camps[b].spend - camps[a].spend;}).forEach(function(c) {
    var d = camps[c];
    var isGmv = d.type === 'gmv_max';
    var ctr = d.impressions > 0 ? (d.clicks/d.impressions*100).toFixed(2) + '%' : '—';
    campHtml += '<tr><td style="font-weight:600">' + c + '</td>';
    campHtml += '<td style="text-align:right"><span style="color:' + (isGmv ? 'var(--gold)' : 'var(--green)') + ';font-size:11px;text-transform:uppercase">' + (isGmv ? 'GMV Max' : 'TikTok Ads') + '</span></td>';
    campHtml += '<td style="text-align:right">' + fmt(d.spend) + '</td>';
    campHtml += '<td style="text-align:right">' + (d.impressions > 0 ? fmtN(d.impressions) : '—') + '</td>';
    campHtml += '<td style="text-align:right">' + (d.clicks > 0 ? fmtN(d.clicks) : '—') + '</td>';
    campHtml += '<td style="text-align:right">' + ctr + '</td>';
    campHtml += '<td style="text-align:right">' + (d.conversions > 0 ? fmtN(d.conversions) : '—') + '</td>';
    campHtml += '<td style="text-align:right">' + d.days + '</td></tr>';
  });
  campHtml += '</tbody></table>';

  // Daily metrics table
  var dailyAgg = {};
  tt.forEach(function(r) {
    if (!dailyAgg[r.date]) dailyAgg[r.date] = {spend:0,impressions:0,clicks:0,conversions:0,reach:0};
    dailyAgg[r.date].spend += r.spend;
    dailyAgg[r.date].impressions += r.impressions;
    dailyAgg[r.date].clicks += r.clicks;
    dailyAgg[r.date].conversions += r.conversions;
    dailyAgg[r.date].reach += r.reach;
  });
  var dHtml = '<div class="section-title">Daily Metrics</div>';
  dHtml += '<table><thead><tr><th>Date</th><th>Day</th><th style="text-align:right">Spend</th><th style="text-align:right">Impressions</th><th style="text-align:right">Clicks</th><th style="text-align:right">CTR</th><th style="text-align:right">Conversions</th></tr></thead><tbody>';
  Object.keys(dailyAgg).sort().forEach(function(date) {
    var d = dailyAgg[date];
    var ctr = d.impressions > 0 ? (d.clicks/d.impressions*100).toFixed(2) + '%' : '—';
    dHtml += '<tr><td style="font-weight:600">' + fmtDate(date) + '</td><td>' + getDayShort(date) + '</td>';
    dHtml += '<td style="text-align:right">' + fmt(d.spend) + '</td>';
    dHtml += '<td style="text-align:right">' + (d.impressions > 0 ? fmtN(d.impressions) : '—') + '</td>';
    dHtml += '<td style="text-align:right">' + (d.clicks > 0 ? fmtN(d.clicks) : '—') + '</td>';
    dHtml += '<td style="text-align:right">' + ctr + '</td>';
    dHtml += '<td style="text-align:right">' + (d.conversions > 0 ? d.conversions : '—') + '</td></tr>';
  });
  dHtml += '</tbody></table>';
  document.getElementById('tiktokDailyTable').innerHTML = campHtml + dHtml;
}



function renderVibe() {
  var vibe = filterByDate(VIBE_DATA, dFrom, dTo);
  var totalSpend = vibe.reduce(function(s,r){return s+r.spend;},0);
  var totalImpressions = vibe.reduce(function(s,r){return s+r.impressions;},0);
  var avgCPM = totalImpressions > 0 ? (totalSpend/totalImpressions*1000).toFixed(2) : '0.00';

  var html = '';
  html += '<div class="card"><h3>Total Spend</h3><div class="value">' + fmt(totalSpend) + '</div></div>';
  html += '<div class="card"><h3>Total Impressions</h3><div class="value">' + fmtN(totalImpressions) + '</div></div>';
  html += '<div class="card"><h3>Avg CPM</h3><div class="value">' + fmt(parseFloat(avgCPM)) + '</div></div>';
  document.getElementById('vibeCards').innerHTML = html;

  var vCamps = {};
  vibe.forEach(function(r) {
    if (!vCamps[r.campaign]) vCamps[r.campaign] = {spend:0,impressions:0,days:0};
    vCamps[r.campaign].spend += r.spend;
    vCamps[r.campaign].impressions += r.impressions;
    vCamps[r.campaign].days += 1;
  });
  var campHtml = '<table><thead><tr><th>Campaign</th><th style="text-align:right">Spend</th><th style="text-align:right">Impressions</th><th style="text-align:right">CPM</th><th style="text-align:right">Days Active</th></tr></thead><tbody>';
  Object.keys(vCamps).forEach(function(name) {
    var c = vCamps[name];
    var cpm = c.impressions > 0 ? (c.spend / c.impressions * 1000).toFixed(2) : '0.00';
    campHtml += '<tr><td style="font-weight:600">' + name + '</td>';
    campHtml += '<td style="text-align:right">' + fmt(c.spend) + '</td>';
    campHtml += '<td style="text-align:right">' + fmtN(c.impressions) + '</td>';
    campHtml += '<td style="text-align:right">' + fmt(parseFloat(cpm)) + '</td>';
    campHtml += '<td style="text-align:right">' + c.days + '</td></tr>';
  });
  campHtml += '</tbody></table>';
  document.getElementById('vibeCampaignTable').innerHTML = campHtml;

  var dates = [];
  var dateMap = {};
  vibe.forEach(function(r) {
    if (!dateMap[r.date]) { dateMap[r.date] = {spend:0,impressions:0}; dates.push(r.date); }
    dateMap[r.date].spend += r.spend;
    dateMap[r.date].impressions += r.impressions;
  });
  dates.sort();
  var dHtml = '<table><thead><tr><th>Date</th><th>Day</th><th style="text-align:right">Spend</th><th style="text-align:right">Impressions</th><th style="text-align:right">CPM</th></tr></thead><tbody>';
  dates.forEach(function(d) {
    var r = dateMap[d];
    var cpm = r.impressions > 0 ? (r.spend / r.impressions * 1000).toFixed(2) : '0.00';
    dHtml += '<tr><td style="font-weight:600">' + fmtDate(d) + '</td><td>' + getDayShort(d) + '</td>';
    dHtml += '<td style="text-align:right">' + fmt(r.spend) + '</td>';
    dHtml += '<td style="text-align:right">' + fmtN(r.impressions) + '</td>';
    dHtml += '<td style="text-align:right">' + fmt(parseFloat(cpm)) + '</td></tr>';
  });
  dHtml += '</tbody></table>';
  document.getElementById('vibeDailyTable').innerHTML = dHtml;
}



